from pydantic import BaseModel, ValidationError
from typing import List, Optional

class ProductItem(BaseModel):
    name: str
    price: float = Field(gt=0)
    category: str
    in_stock: Optional[bool] = None

def parse_product_output(raw_data: str) -> ProductItem:
    try:
        return ProductItem.model_validate_json(raw_data)
    except ValidationError as e:
        print(f"验证失败: {e}")
        raise

# 模型返回的 JSON 字符串
model_output = '{"name": "AI 导师", "price": 199.0, "category": "软件"}'
product = parse_product_output(model_output)
